"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";

interface SearchBarProps {
    size?: "lg" | "sm";
    defaultAI?: boolean;
}

export default function SearchBar({ size = "lg", defaultAI = false }: SearchBarProps) {
    const [keyword, setKeyword] = useState("");
    const [location, setLocation] = useState("");
    const [useAI, setUseAI] = useState(defaultAI);
    const [isLoading, setIsLoading] = useState(false);
    const router = useRouter();

    const handleSearch = async (e: React.FormEvent) => {
        e.preventDefault();
        
        if (useAI && keyword) {
            setIsLoading(true);
            try {
                const response = await fetch("/api/ai/search", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ query: keyword, limit: 20 }),
                });
                const data = await response.json();
                
                if (data.success && data.jobs) {
                    const params = new URLSearchParams();
                    params.set("q", keyword);
                    params.set("ai", "true");
                    if (location) params.set("loc", location);
                    router.push(`/jobs?${params.toString()}`);
                } else {
                    const params = new URLSearchParams();
                    params.set("q", keyword);
                    if (location) params.set("loc", location);
                    router.push(`/jobs?${params.toString()}`);
                }
            } catch (error) {
                console.error("AI search failed:", error);
                const params = new URLSearchParams();
                params.set("q", keyword);
                if (location) params.set("loc", location);
                router.push(`/jobs?${params.toString()}`);
            } finally {
                setIsLoading(false);
            }
        } else {
            const params = new URLSearchParams();
            if (keyword) params.set("q", keyword);
            if (location) params.set("loc", location);
            router.push(`/jobs?${params.toString()}`);
        }
    };

    const isLg = size === "lg";

    return (
        <form
            onSubmit={handleSearch}
            style={{
                display: "flex",
                gap: isLg ? "0" : "0.5rem",
                background: "var(--bg-card)",
                borderRadius: isLg ? "12px" : "8px",
                border: "2px solid var(--border)",
                boxShadow: "var(--shadow-md)",
                overflow: isLg ? "hidden" : "visible",
                flexWrap: isLg ? undefined : "wrap",
                transition: "border-color 200ms",
                flexDirection: isLg ? "row" : "column",
            }}
            onFocus={(e) => ((e.currentTarget as HTMLFormElement).style.borderColor = "var(--primary)")}
            onBlur={(e) => ((e.currentTarget as HTMLFormElement).style.borderColor = "var(--border)")}
        >
            {/* Keyword input */}
            <div style={{ display: "flex", alignItems: "center", flex: 2, padding: isLg ? "0 1.25rem" : "0.75rem", minWidth: 0 }}>
                <svg
                    width="18"
                    height="18"
                    fill="none"
                    stroke="var(--primary)"
                    strokeWidth="2"
                    viewBox="0 0 24 24"
                    style={{ flexShrink: 0, marginRight: "0.5rem" }}
                >
                    <circle cx="11" cy="11" r="8" />
                    <path strokeLinecap="round" d="M21 21l-4.35-4.35" />
                </svg>
                <input
                    type="text"
                    placeholder="Tên công việc, kỹ năng, công ty..."
                    value={keyword}
                    onChange={(e) => setKeyword(e.target.value)}
                    disabled={isLoading}
                    style={{
                        border: "none",
                        outline: "none",
                        background: "transparent",
                        fontFamily: "inherit",
                        fontSize: isLg ? "0.9375rem" : "0.875rem",
                        color: "var(--text)",
                        width: "100%",
                        padding: isLg ? "1rem 0" : "0.5rem 0",
                    }}
                />
            </div>

            {/* Divider */}
            {isLg && (
                <div style={{ width: "1.5px", background: "var(--border)", margin: "0.75rem 0" }} />
            )}

            {/* Location input */}
            <div style={{ display: "flex", alignItems: "center", flex: 1, padding: isLg ? "0 1.25rem" : "0.75rem", minWidth: 0 }}>
                <svg
                    width="18"
                    height="18"
                    fill="none"
                    stroke="var(--primary)"
                    strokeWidth="2"
                    viewBox="0 0 24 24"
                    style={{ flexShrink: 0, marginRight: "0.5rem" }}
                >
                    <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        d="M17.657 16.657L13.414 20.9a1.998 1.998 0 0 1-2.827 0l-4.244-4.243a8 8 0 1 1 11.314 0z"
                    />
                    <path strokeLinecap="round" strokeLinejoin="round" d="M15 11a3 3 0 1 1-6 0 3 3 0 0 1 6 0z" />
                </svg>
                <input
                    type="text"
                    placeholder="Địa điểm: Hà Nội, TP.HCM..."
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    disabled={isLoading}
                    style={{
                        border: "none",
                        outline: "none",
                        background: "transparent",
                        fontFamily: "inherit",
                        fontSize: isLg ? "0.9375rem" : "0.875rem",
                        color: "var(--text)",
                        width: "100%",
                        padding: isLg ? "1rem 0" : "0.5rem 0",
                    }}
                />
            </div>

            {/* AI Toggle */}
            <label
                style={{
                    display: "flex",
                    alignItems: "center",
                    gap: "0.5rem",
                    padding: isLg ? "0 1rem" : "0.5rem",
                    cursor: "pointer",
                    userSelect: "none",
                    borderLeft: isLg ? "1px solid var(--border)" : "none",
                }}
                title="Tìm kiếm AI thông minh"
            >
                <input
                    type="checkbox"
                    checked={useAI}
                    onChange={(e) => setUseAI(e.target.checked)}
                    style={{ display: "none" }}
                />
                <div
                    style={{
                        width: "36px",
                        height: "20px",
                        borderRadius: "10px",
                        background: useAI ? "var(--primary)" : "var(--border)",
                        position: "relative",
                        transition: "background 200ms",
                    }}
                >
                    <div
                        style={{
                            width: "16px",
                            height: "16px",
                            borderRadius: "50%",
                            background: "#fff",
                            position: "absolute",
                            top: "2px",
                            left: useAI ? "18px" : "2px",
                            transition: "left 200ms",
                        }}
                    />
                </div>
                <svg
                    width="16"
                    height="16"
                    fill="none"
                    stroke={useAI ? "var(--primary)" : "var(--text-muted)"}
                    strokeWidth="2"
                    viewBox="0 0 24 24"
                >
                    <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2z" />
                    <path d="M12 6v6l4 2" />
                </svg>
                <span style={{ fontSize: "0.8125rem", color: useAI ? "var(--primary)" : "var(--text-muted)" }}>
                    AI
                </span>
            </label>

            {/* Submit */}
            <button
                type="submit"
                className="btn-primary"
                disabled={isLoading}
                style={{
                    borderRadius: isLg ? "0 10px 10px 0" : "8px",
                    padding: isLg ? "1rem 2rem" : "0.75rem 1.25rem",
                    fontSize: "0.9375rem",
                    margin: isLg ? "0" : "0.5rem 0",
                    opacity: isLoading ? 0.7 : 1,
                    cursor: isLoading ? "wait" : "pointer",
                    display: "flex",
                    alignItems: "center",
                    gap: "0.5rem",
                }}
            >
                {isLoading ? (
                    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24" style={{ animation: "spin 1s linear infinite" }}>
                        <path d="M12 2v4m0 12v4M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M2 12h4m12 0h4M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83" />
                    </svg>
                ) : (
                    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                        <circle cx="11" cy="11" r="8" />
                        <path strokeLinecap="round" d="M21 21l-4.35-4.35" />
                    </svg>
                )}
                {isLoading ? "Đang tìm..." : "Tìm kiếm"}
            </button>
            <style jsx>{`
                @keyframes spin {
                    from { transform: rotate(0deg); }
                    to { transform: rotate(360deg); }
                }
            `}</style>
        </form>
    );
}
